    ['backslash trick /\\host', '/\\evil.example'],
    ['bare /app (no trailing slash/content)', '/app'],
    ['a non-/app internal path', '/login'],
    ['a root path', '/'],
    ['a relative path', 'app/x'],
    ['a javascript: scheme', 'javascript:alert(1)'],
    ['an empty string', ''],
