  });

  it('Create with no server selected toasts a validation error and does not POST', async () => {
    const { client, post } = makeClient();
    const w = mountPage(client);
    await flushPromises();
    await findBtnByText(w, 'New Invite')!.trigger('click');
    await flushPromises();
